const HIGH_RISK_LARGE_TEXT_TOOL_NAMES = new Set(["exec", "read"]);
const HIGH_RISK_PERSISTED_TEXT_HARD_CAP = 1200;
function isHighRiskLargeTextToolResult(msg) {
	if (!isToolResultMessage(msg)) return false;
	const toolName = normalizeOptionalLowercaseString(msg.toolName) ?? "";
	return HIGH_RISK_LARGE_TEXT_TOOL_NAMES.has(toolName);
}
function aggressivelyCompactHighRiskPersistedToolResult(msg, rawText) {
	const hardCap = HIGH_RISK_PERSISTED_TEXT_HARD_CAP;
	if (rawText.length <= hardCap) return replaceToolResultText(msg, rawText);
	const prefixBudget = 700;
	const suffixBudget = 300;
	const head = rawText.slice(0, prefixBudget).trimEnd();
	const tail = rawText.slice(-suffixBudget).trimStart();
	const omitted = Math.max(1, rawText.length - head.length - tail.length);
	const lines = rawText.split(/\r?\n/);
	const lineCount = lines.length;
	const summary = `[persisted ${msg.toolName || "tool"} output compacted for session safety, originalChars=${rawText.length}, originalLines=${lineCount}, keptHeadChars=${head.length}, keptTailChars=${tail.length}, omittedChars=${omitted}]`;
	return replaceToolResultText(msg, `${summary}\n\n${head}\n\n[... ${omitted} chars omitted from persisted ${msg.toolName || "tool"} output ...]\n\n${tail}`);
}
function truncateToolResultToChars(msg, maxChars, cache) {
	if (!isToolResultMessage(msg)) return msg;
	const estimatedChars = estimateMessageCharsCached(msg, cache);
	if (estimatedChars <= maxChars) return msg;
	const rawText = getToolResultText(msg);
	if (!rawText) return replaceToolResultText(msg, formatContextLimitTruncationNotice(Math.max(1, estimateBudgetToTextBudget(Math.max(estimatedChars - maxChars, 1)))));
	if (isHighRiskLargeTextToolResult(msg)) {
		return aggressivelyCompactHighRiskPersistedToolResult(msg, rawText);
	}
	const textBudget = estimateBudgetToTextBudget(maxChars);
	if (textBudget <= 0) return replaceToolResultText(msg, formatContextLimitTruncationNotice(rawText.length));
	if (rawText.length <= textBudget) return replaceToolResultText(msg, rawText);
	return replaceToolResultText(msg, truncateTextToBudget(rawText, textBudget));
}
